public sealed class CreateDeliveryRouteUseCase(IDeliveryRouteRepository repo, ILogger<CreateDeliveryRouteUseCase> logger) { public async Task<Result<DeliveryRouteResponse>> ExecuteAsync(CreateDeliveryRouteRequest request, CancellationToken ct) { try { return Result<DeliveryRouteResponse>.Success(await repo.CreateAsync(request, ct)); } catch (Exception ex) { logger.LogError(ex, "Create route failed"); return Result<DeliveryRouteResponse>.Failure(ex.Message); } } }
public sealed class UpdateDeliveryRouteUseCase(IDeliveryRouteRepository repo, ILogger<UpdateDeliveryRouteUseCase> logger) { public async Task<Result<DeliveryRouteResponse?>> ExecuteAsync(Guid tenantId, Guid id, UpdateDeliveryRouteRequest request, CancellationToken ct) { try { return Result<DeliveryRouteResponse?>.Success(await repo.ChangeStatusAsync(tenantId, id, request.Status, ct)); } catch (Exception ex) { logger.LogError(ex, "Update route failed"); return Result<DeliveryRouteResponse?>.Failure(ex.Message); } } }
