public sealed class StartDeliveryRouteUseCase(IDeliveryRouteRepository r, ILogger<StartDeliveryRouteUseCase> l) { public Task<Result<DeliveryRouteResponse?>> ExecuteAsync(Guid t, Guid id, CancellationToken c) => Change(r, l, t, id, "em_rota", c); static async Task<Result<DeliveryRouteResponse?>> Change(IDeliveryRouteRepository r, ILogger l, Guid t, Guid id, string s, CancellationToken c) { try { return Result<DeliveryRouteResponse?>.Success(await r.ChangeStatusAsync(t, id, s, c)); } catch (Exception ex) { l.LogError(ex, "Route status failed"); return Result<DeliveryRouteResponse?>.Failure(ex.Message); } } }
